command.text:
        /* <flatten type="Javascript"> */
var f = this, id = f.get_id(), g = f.grid, v = f._language == 'v';
var e = (v ? 'Hóa đơn gốc phải khác với hóa đơn thay thế.' : 'Original Invoice should have different Replacement Invoice.');
if (f.getItemValue('stt_rec0') == f.getItemValue('stt_rec1')) {
  $func.hideWait(id);
  $message.show(e, String.format('$find(\'{0}\').getItem(\'so_ct0\').focus()', id));
  f._checked = false;
}

var g2 = f.getItem('hddt01ct')._controlBehavior;
if (f._checked && g2._rowCount > 1)
  var gID = g2.get_id(), t = g2._getColumnOrder('line_nbr0');
  e = (v ? 'Tồn tại dòng trên chứng từ gốc trùng nhau.' : 'The original invoice\'s line already existed.');
  for (var i = 1; i < g2._rowCount; i++) {
    if (!f._checked) break;
    for (var j = i + 1; j <= g2._rowCount; j++) {
      var d1 = g2._getItemValue(i, t).valueOf(), d2 = g2._getItemValue(j, t).valueOf();
      if (d1 == d2) {
        g2._errorWarningObject = g2._getItem(j, t);
        $func.hideWait(id);
        $message.show(e, String.format('$find(\'{0}\').focus(\'{1}\');$find(\'{2}\')._errorWarningObject.focus()', id, 'hddt01ct', gID));
        f._checked = false;
        break;
      }
    }
  }
}
/* </flatten> */

script.text:

function show$&Identity;$(f) {
  var g = f.grid;
  if (g._$voucherCode != 'HDA') {
    setItemHidden(f, 'cn_qui_trinh', true);
    var t = $find(f._tabContainer.get_id());
    if (t) {
      var b = t._element.parentElement.getElementsByClassName('TabDlgBottom');
      t._element.style.display = 'none';
      if (b) b[0].style.display = 'none';
    }
  }
}
function active$&Identity;$(f) {set$&Identity;$DefaultValue(f);}
function scatter$&Identity;$(f) {set$&Identity;$DefaultValue(f);}
function close$&Identity;$(f) {}
function showForm$&Identity;(o, n) {
  var f = document.body._form, g = f.grid;
  if (f._action != 'View') {
    g._$typeInv = n;
    g.showForm('&Identity;Filter');
  }
}

function set$&Identity;$DefaultValue(f) {
  var g = f.grid;
  f.setReadOnlyFields('so_ct0, ngay_ct0, so_ct1, ngay_ct1');
  if (f._action == 'New') f.setItemValues('ma_dvcs, ma_ct', [g._$unit, g._$voucherCode]);
  document.body._form = f;
}
/* <flatten type="Javascript"> */
function setItemHidden(f, c, b) {
  var a = c.split(','), o;
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      o = f.getItem($func.trim(a[i]));
      if (b) o.field.AllowNulls = b;
      $common.setVisible(o.parentNode.parentNode.parentNode, !b);
    }
  }
}
/* </flatten> */
